noncompliant:
// Noncompliant: redundant return
void MyMethod()
{
    DoSomething();
    return; // Redundant - method would return anyway
}

// Noncompliant: redundant continue
for (int i = 0; i < 10; i++)
{
    DoSomething(i);
    continue; // Redundant - loop would continue anyway
}

// Noncompliant: unreachable code after return
int GetValue()
{
    return 42;
    Console.WriteLine("Never executed"); // Unreachable
}

compliant:
// Compliant: return with value
int GetValue()
{
    return 42;
}

// Compliant: conditional return
void MyMethod(bool condition)
{
    if (condition)
    {
        return; // Early exit - not redundant
    }
    DoSomething();
}

// Compliant: conditional continue
for (int i = 0; i < 10; i++)
{
    if (ShouldSkip(i))
    {
        continue; // Skip to next iteration - not redundant
    }
    DoSomething(i);
}
